function useCityConfig(): CityConfig {
  const slug = (window.location.pathname.split("/").filter(Boolean)[0] || "seattle").toLowerCase() as CitySlug;
  return CITY_CONFIGS[slug] ?? CITY_CONFIGS.seattle;
}

