function QuickMenuSection({ onNavigate }: { onNavigate?: (tab: number, subTab?: number) => void }) {
  const { lang } = useI18n();
  const city = useCityConfig();
  const ko = lang === "ko";
  const [wcCollapsed, setWcCollapsed] = useState(() => {
    try { return localStorage.getItem("wc2026_collapsed") === "1"; } catch { return false; }
  });
  const isWCCity = isWorldCupActive(city.slug);

  const collapseWC = () => {
    setWcCollapsed(true);
    try { localStorage.setItem("wc2026_collapsed", "1"); } catch {}
  };
  const expandWC = () => {
    setWcCollapsed(false);
    try { localStorage.removeItem("wc2026_collapsed"); } catch {}
  };

  // 여정 4단계 — 각 Row에 레이블
  const PHASES = [
    { labelKo: "✈️ Day 0 — 도착·입국",   labelEn: "✈️ Day 0 — Arrival & Entry" },
    { labelKo: "🏠 첫 주 — 생활 기반",    labelEn: "🏠 Week 1 — Essential Setup" },
    { labelKo: "🌿 생활 · 커뮤니티",       labelEn: "🌿 Daily Life & Community" },
    { labelKo: "📈 심화 · 성장",           labelEn: "📈 Growth & More" },
  ];

  const renderQMItem = (item: typeof QUICK_MENU[0], i: number) => {
    const IconComp = QM_ICON_MAP[item.icon];
    return (
      <button key={i} onClick={() => onNavigate?.(item.tab, item.subTab)} style={{
        background: "none", border: "none", cursor: "pointer",
        display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
        padding: 0, WebkitTapHighlightColor: "transparent",
      }}
      onTouchStart={e => { const el = e.currentTarget.querySelector('.qm-icon') as HTMLElement; if (el) { el.style.transform = "scale(0.86)"; el.style.opacity = "0.82"; } }}
      onTouchEnd={e => { const el = e.currentTarget.querySelector('.qm-icon') as HTMLElement; if (el) { el.style.transform = "scale(1)"; el.style.opacity = "1"; } }}
      onMouseDown={e => { const el = e.currentTarget.querySelector('.qm-icon') as HTMLElement; if (el) { el.style.transform = "scale(0.88)"; el.style.opacity = "0.82"; } }}
      onMouseUp={e => { const el = e.currentTarget.querySelector('.qm-icon') as HTMLElement; if (el) { el.style.transform = "scale(1)"; el.style.opacity = "1"; } }}
      onMouseLeave={e => { const el = e.currentTarget.querySelector('.qm-icon') as HTMLElement; if (el) { el.style.transform = "scale(1)"; el.style.opacity = "1"; } }}>
        <div className="qm-icon" style={{
          width: 62, height: 62, borderRadius: 16,
          background: item.color,
          boxShadow: `0 5px 16px ${item.color}66, 0 1px 4px rgba(0,0,0,0.14), inset 0 1px 0 rgba(255,255,255,0.28)`,
          display: "flex", alignItems: "center", justifyContent: "center",
          transition: "transform 0.15s cubic-bezier(0.34,1.56,0.64,1), opacity 0.12s ease",
          flexShrink: 0,
        }}>
          {IconComp && <IconComp size={29} color="#fff" strokeWidth={1.7} />}
        </div>
        <span style={{
          fontFamily: "-apple-system, 'SF Pro Text', 'Noto Sans KR', sans-serif",
          fontWeight: 500, fontSize: 11, color: "#1C1C1E",
          letterSpacing: "-0.15px", textAlign: "center", lineHeight: 1.25, width: "100%",
        }}>
          {ko ? item.labelKo : item.labelEn}
        </span>
      </button>
    );
  };

  return (
    <div style={{ padding: "20px 20px 16px", background: "#fff" }}>
      <div style={{
        fontFamily: "-apple-system, 'SF Pro Display', 'Noto Sans KR', sans-serif",
        fontWeight: 800, fontSize: 17, color: "#1C1C1E",
        letterSpacing: "-0.5px", marginBottom: 14,
      }}>
        {ko ? "바로 가기" : "Quick Access"}
      </div>

      {/* ── 월드컵 카드 (WC 개최 도시 + 기간 중만) — 펼침/접힘 토글 */}
      {isWCCity && (
        wcCollapsed ? (
          /* 접힌 상태: 작은 칩 */
          <button onClick={expandWC} style={{
            marginBottom: 14, display: "flex", alignItems: "center", gap: 8,
            background: "linear-gradient(90deg, #C8102E, #003087)",
            border: "none", borderRadius: 20, padding: "7px 14px", cursor: "pointer",
            boxShadow: "0 2px 10px rgba(200,16,46,0.25)",
          }}>
            <span style={{ fontSize: 16 }}>⚽</span>
            <span style={{ fontFamily: "Manrope,sans-serif", fontWeight: 800, fontSize: 12, color: "#fff" }}>
              {ko ? "FIFA 월드컵 2026 — 탭하여 열기" : "FIFA World Cup 2026 — Tap to expand"}
            </span>
            <span style={{ fontFamily: "Manrope,sans-serif", fontSize: 14, color: "rgba(255,255,255,0.7)", marginLeft: 2 }}>›</span>
          </button>
        ) : (
          /* 펼친 상태: 풀 카드 */
          <div style={{
            marginBottom: 16, borderRadius: 16, overflow: "hidden",
            background: "linear-gradient(120deg, #C8102E 0%, #003087 100%)",
            boxShadow: "0 4px 20px rgba(200,16,46,0.3)",
            position: "relative",
          }}>
            <div style={{ position: "absolute", right: -8, top: -12, fontSize: 72, opacity: 0.12, userSelect: "none" }}>⚽</div>
            <div style={{ padding: "12px 14px" }}>
              <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between" }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontFamily: "Manrope,sans-serif", fontWeight: 900, fontSize: 10, color: "rgba(255,255,255,0.7)", letterSpacing: "1.2px", textTransform: "uppercase", marginBottom: 3 }}>
                    FIFA WORLD CUP 2026
                  </div>
                  <div style={{ fontFamily: "Manrope,sans-serif", fontWeight: 800, fontSize: 15, color: "#fff", lineHeight: 1.25, marginBottom: 6 }}>
                    ⚽ {ko ? `${city.nameKo} 월드컵 경기장 & 교통 가이드` : `${city.nameEn} World Cup — Venues & Transit`}
                  </div>
                  <div style={{ fontFamily: "Manrope,sans-serif", fontSize: 11, color: "rgba(255,255,255,0.8)", lineHeight: 1.5, marginBottom: 10 }}>
                    {ko ? "경기 일정 · 경기장 교통 · 한식당 · 환전 정보" : "Match schedule · Stadium transit · Korean food · Exchange"}
                  </div>
                  <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                    <button onClick={() => onNavigate?.(4, 0)} style={{
                      background: "#fff", border: "none", borderRadius: 20, cursor: "pointer",
                      padding: "7px 16px",
                      fontFamily: "Manrope,sans-serif", fontWeight: 800, fontSize: 12, color: "#C8102E",
                    }}>
                      {ko ? "탐방 가이드 보기 →" : "View Guide →"}
                    </button>
                  </div>
                </div>
                {/* 접기 버튼 */}
                <button onClick={collapseWC} style={{
                  background: "rgba(255,255,255,0.15)", border: "none", borderRadius: "50%",
                  width: 28, height: 28, cursor: "pointer", display: "flex",
                  alignItems: "center", justifyContent: "center", flexShrink: 0,
                  fontFamily: "Manrope,sans-serif", fontSize: 14, color: "#fff",
                }} title={ko ? "접기" : "Collapse"}>−</button>
              </div>
            </div>
          </div>
        )
      )}

      {/* ── 4단계 여정 순서 Quick Menu */}
      {[0, 1, 2, 3].map(phase => (
        <div key={phase} style={{ marginBottom: phase < 3 ? 18 : 0 }}>
          {/* 단계 레이블 */}
          <div style={{
            fontFamily: "-apple-system, 'SF Pro Text', 'Noto Sans KR', sans-serif",
            fontWeight: 600, fontSize: 11, color: "#8E8E93",
            letterSpacing: "0.2px", marginBottom: 12, paddingLeft: 2,
          }}>
            {ko ? PHASES[phase].labelKo : PHASES[phase].labelEn}
          </div>
          {/* 4열 아이콘 그리드 */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", columnGap: 8 }}>
            {QUICK_MENU.slice(phase * 4, phase * 4 + 4).map((item, i) => renderQMItem(item, i))}
          </div>
        </div>
      ))}
    </div>
  );
}

